{
  "guidedPractice": {
    "title": "Guided Practice: Categorising Network Components",
    "objective": "Categorise a specific voltage level and a generation source into their correct classifications based on the UK supply chain.",
    "retrievalTextLines": [
      "To classify a component, follow these steps:",
      "1. Check if the item is a fuel source or technology (Generation).",
      "2. Check if the item is a specific high voltage: 132 kV, 275 kV, or 400 kV (Transmission).",
      "3. Remember: 1 kV = 1,000 Volts."
    ],
    "questionText": "A technical diagram shows a '275,000 Volt' line and a 'Wind' turbine farm. Convert the voltage to kV and classify both items as either a 'Generation Method' or a 'Transmission Voltage'.",
    "answerGuidance": [
      "275 kV is a Transmission Voltage",
      "Wind is a Generation Method"
    ],
    "hint": "Divide 275,000 by 1,000 to get the kV. Check the list of generation methods for 'Wind'."
  },
  "practice": {
    "title": "Independent Practice: Transmission Standards",
    "objective": "Identify the three specific voltage levels used for the UK national transmission network.",
    "retrievalTextLines": [
      "The transmission network acts as the 'motorway' of the grid, using only three specific high-voltage levels before the electricity is stepped down for local distribution."
    ],
    "questionText": "Identify the three specific voltage levels (expressed in kV) that are used for the transmission of electricity in the UK.",
    "answerGuidance": [
      "132 kV, 275 kV, 400 kV"
    ],
    "hint": "Think of the three highest voltage levels mentioned in the source text, all of which are above 100 kV."
  }
}

{
  "integrative": {
    "title": "Integrative Close: From Source to Grid",
    "objective": "Synthesize the identification of a specific generation method with its corresponding high-voltage transmission level in a real-world scenario.",
    "retrievalTextLines": [
      "To understand the UK supply chain, you must link the source of power to its transport method. Generation involves converting energy (like wind, gas, or nuclear) into electricity. Transmission then moves that power across the country using only three specific high-voltage levels: 132 kV, 275 kV, and 400 kV.",
      "As an electrician, you must be able to look at a power source and the resulting grid voltage to correctly identify where you are in the supply chain."
    ],
    "questionText": "A new 'Biomass' power plant is being commissioned to supply the National Grid. The output is stepped up to 132,000 Volts for long-distance transport. Identify the generation method used in this scenario and state the transmission voltage using the correct technical unit (kV).",
    "answerGuidance": [
      "Generation Method: Biomass",
      "Transmission Voltage: 132 kV"
    ],
    "hint": "Check the list of ten generation methods for the fuel source mentioned, and remember that 1 kV equals 1,000 Volts."
  }
}

